const crypto = require('crypto');
const item = $input.first().json;
const headers = item.headers || {};
const body = item.body || {};
const ref = (body && body.actionRef) || null;
function respond(httpCode, response) { return [{ json: { httpCode, response } }]; }
function fail(httpCode, status, message) { return respond(httpCode, { ok: false, actionRef: ref, status, message, result: null, deduped: false }); }

// 1) Static secret: x-webhook-secret must equal ORIA_N8N_WEBHOOK_SECRET
const expectedSecret = $env.ORIA_N8N_WEBHOOK_SECRET;
if (!expectedSecret) return fail(500, 'config_error', 'ORIA_N8N_WEBHOOK_SECRET is not set in n8n.');
if (headers['x-webhook-secret'] !== expectedSecret) return fail(401, 'secret_error', 'Invalid or missing x-webhook-secret.');

// 2) HMAC: Oria signs `${timestamp}.${canonicalBody}` with ORIA_WEBHOOK_SIGNING_SECRET
const signingSecret = $env.ORIA_WEBHOOK_SIGNING_SECRET;
if (!signingSecret) return fail(500, 'config_error', 'ORIA_WEBHOOK_SIGNING_SECRET is not set in n8n.');
const ts = headers['x-orya-timestamp'];
const sig = headers['x-orya-signature'];
if (!ts || !sig) return fail(401, 'secret_error', 'Missing HMAC headers (x-orya-timestamp / x-orya-signature).');
const canonical = JSON.stringify(body);
const expected = crypto.createHmac('sha256', signingSecret).update(ts + '.' + canonical).digest('hex');
let sigOk = false;
try { const a = Buffer.from(sig, 'hex'); const b = Buffer.from(expected, 'hex'); sigOk = a.length === b.length && crypto.timingSafeEqual(a, b); } catch (e) { sigOk = false; }
if (!sigOk) return fail(401, 'secret_error', 'HMAC signature mismatch.');

// 3) Required-field validation
const required = ['actionRef', 'agentId', 'skillId', 'client', 'email', 'actionType', 'missionId'];
for (const k of required) { if (typeof body[k] !== 'string' || body[k].length === 0) return fail(400, 'validation_error', 'Missing or invalid field: ' + k); }

// 4) Routing: only the authorized pair (hermes + task.create)
if (body.agentId !== 'hermes' || body.skillId !== 'task.create') return fail(400, 'validation_error', 'Unsupported route ' + body.agentId + '/' + body.skillId + '. Only hermes/task.create is enabled.');

// (test hook) simulate a transient downstream error -> retryable, NOT recorded
if (body.data && body.data.simulate === 'transient') return fail(503, 'transient_error', 'Simulated transient downstream error (retryable).');

// 5) Dedup by actionRef (workflow static data, persisted across executions)
const sd = $getWorkflowStaticData('global');
if (!sd.seenActionRefs) sd.seenActionRefs = {};
const seen = sd.seenActionRefs;
if (seen[body.actionRef]) return respond(200, { ok: true, actionRef: body.actionRef, status: 'deduped', message: 'actionRef already processed; not executed again.', result: seen[body.actionRef].result, deduped: true });

// 6) SAFE / DRY-RUN execution -- no real side effect
const result = { wouldExecute: true, agentId: body.agentId, skillId: body.skillId, actionType: body.actionType, client: body.client, dryRun: true, note: 'DRY-RUN: action WOULD have executed. No email, no external mutation.' };
seen[body.actionRef] = { at: new Date().toISOString(), result };
const keys = Object.keys(seen);
if (keys.length > 1000) { for (const k of keys.slice(0, 100)) delete seen[k]; }

return respond(200, { ok: true, actionRef: body.actionRef, status: 'ok', message: 'DRY-RUN success: action accepted and recorded (not executed).', result, deduped: false });
